+    /// Root seed used for the test execution.
+    pub seed: u64,
+    /// Scenario identifier (test name or scenario tag).
+    pub scenario_id: String,
+    /// Entropy seed derived from root.
+    #[serde(skip_serializing_if = "Option::is_none")]
