+pub struct TestEnvironment {
+    context: TestContext,
+    ports: PortAllocator,
+    services: Vec<ServiceEntry>,
+    cleanup_fns: Vec<Box<dyn FnOnce()>>,
+    torn_down: bool,
+}
+
+impl std::fmt::Debug for TestEnvironment {
